300→// points[0] to be a histogram. It returns nil if any other Point in points is
301→// not a histogram, and a warning wrapped in an annotation in that case.
302→// Otherwise, it returns the calculated histogram and an empty annotation.
303→func histogramRate(points []HPoint, isCounter bool, labels labels.Labels, pos posrange.PositionRange) (*histogram.FloatHistogram, annotations.Annotations) {
304→	var (
305→		prev               = points[0].H
306→		usingCustomBuckets = prev.UsesCustomBuckets()
307→		last               = points[len(points)-1].H
308→		annos              annotations.Annotations
309→	)
310→
311→	if last == nil {
312→		return nil, annos.Add(annotations.NewMixedFloatsHistogramsWarning(getMetricName(labels), pos))
313→	}
314→
315→	// We check for gauge type histograms in the loop below, but the loop
316→	// below does not run on the first and last point, so check the first
317→	// and last point now.
318→	if isCounter && (prev.CounterResetHint == histogram.GaugeType || last.CounterResetHint == histogram.GaugeType) {
319→		annos.Add(annotations.NewNativeHistogramNotCounterWarning(getMetricName(labels), pos))
320→	}
321→
322→	// Null out the 1st sample if there is a counter reset between the 1st
323→	// and 2nd. In this case, we want to ignore any incompatibility in the
324→	// bucket layout of the 1st sample because we do not need to look at it.
325→	if isCounter && len(points) > 1 {
326→		second := points[1].H
327→		if second != nil && second.DetectReset(prev) {
328→			prev = &histogram.FloatHistogram{}
329→			prev.Schema = second.Schema
330→			prev.CustomValues = second.CustomValues
331→			usingCustomBuckets = second.UsesCustomBuckets()
332→		}
333→	}
334→
335→	if last.UsesCustomBuckets() != usingCustomBuckets {
336→		return nil, annos.Add(annotations.NewMixedExponentialCustomHistogramsWarning(getMetricName(labels), pos))
337→	}
338→
339→	// First iteration to find out two things:
340→	// - What's the smallest relevant schema?
341→	// - Are all data points histograms?
342→	minSchema := min(last.Schema, prev.Schema)
343→	for _, currPoint := range points[1 : len(points)-1] {
344→		curr := currPoint.H
345→		if curr == nil {
346→			return nil, annotations.New().Add(annotations.NewMixedFloatsHistogramsWarning(getMetricName(labels), pos))
347→		}
348→		if !isCounter {
349→			continue
350→		}
351→		if curr.CounterResetHint == histogram.GaugeType {
352→			annos.Add(annotations.NewNativeHistogramNotCounterWarning(getMetricName(labels), pos))
353→		}
354→		if curr.Schema < minSchema {
355→			minSchema = curr.Schema
356→		}
357→		if curr.UsesCustomBuckets() != usingCustomBuckets {
358→			return nil, annotations.New().Add(annotations.NewMixedExponentialCustomHistogramsWarning(getMetricName(labels), pos))
359→		}
360→	}
361→
362→	h := last.CopyToSchema(minSchema)
363→	// This subtraction may deliberately include conflicting counter resets.
364→	// Counter resets are treated explicitly in this function, so the
365→	// information about conflicting counter resets is ignored here.
366→	_, _, nhcbBoundsReconciled, err := h.Sub(prev)
367→	if err != nil {
368→		if errors.Is(err, histogram.ErrHistogramsIncompatibleSchema) {
369→			return nil, annotations.New().Add(annotations.NewMixedExponentialCustomHistogramsWarning(getMetricName(labels), pos))
370→		}
371→	}
372→	if nhcbBoundsReconciled {
373→		annos.Add(annotations.NewMismatchedCustomBucketsHistogramsInfo(pos, annotations.HistogramSub))
374→	}
375→
376→	if isCounter {
377→		// Second iteration to deal with counter resets.
378→		for _, currPoint := range points[1:] {
379→			curr := currPoint.H
380→			if curr.DetectReset(prev) {
381→				// Counter reset conflict ignored here for the same reason as above.
382→				_, _, nhcbBoundsReconciled, err := h.Add(prev)
383→				if err != nil {
384→					if errors.Is(err, histogram.ErrHistogramsIncompatibleSchema) {
385→						return nil, annotations.New().Add(annotations.NewMixedExponentialCustomHistogramsWarning(getMetricName(labels), pos))
386→					}
387→				}
388→				if nhcbBoundsReconciled {
389→					annos.Add(annotations.NewMismatchedCustomBucketsHistogramsInfo(pos, annotations.HistogramAdd))
390→				}
391→			}
392→			prev = curr
393→		}
394→	} else if points[0].H.CounterResetHint != histogram.GaugeType || points[len(points)-1].H.CounterResetHint != histogram.GaugeType {
395→		annos.Add(annotations.NewNativeHistogramNotGaugeWarning(getMetricName(labels), pos))
396→	}
397→
398→	h.CounterResetHint = histogram.GaugeType
399→	return h.Compact(0), annos
400→}
