552→// Double exponential smoothing is similar to a weighted moving average, where
553→// historical data has exponentially less influence on the current data. It also
554→// accounts for trends in data. The smoothing factor (0 < sf < 1) affects how
555→// historical data will affect the current data. A lower smoothing factor
556→// increases the influence of historical data. The trend factor (0 < tf < 1)
557→// affects how trends in historical data will affect the current data. A higher
558→// trend factor increases the influence. of trends. Algorithm taken from
559→// https://en.wikipedia.org/wiki/Exponential_smoothing .
560→func funcDoubleExponentialSmoothing(vectorVals []Vector, matrixVal Matrix, args parser.Expressions, enh *EvalNodeHelper) (Vector, annotations.Annotations) {
561→	if len(vectorVals) < 2 || len(vectorVals[0]) == 0 || len(vectorVals[1]) == 0 || len(matrixVal) == 0 {
562→		return enh.Out, nil
563→	}
564→	samples := matrixVal[0]
565→	// The smoothing factor argument.
566→	sf := vectorVals[0][0].F
567→
568→	// The trend factor argument.
569→	tf := vectorVals[1][0].F
570→
571→	// Check that the input parameters are valid.
572→	if sf <= 0 || sf >= 1 {
573→		panic(fmt.Errorf("invalid smoothing factor. Expected: 0 < sf < 1, got: %f", sf))
574→	}
575→	if tf <= 0 || tf >= 1 {
576→		panic(fmt.Errorf("invalid trend factor. Expected: 0 < tf < 1, got: %f", tf))
577→	}
578→
579→	l := len(samples.Floats)
580→
581→	// Can't do the smoothing operation with less than two points.
582→	if l < 2 {
583→		// Annotate mix of float and histogram.
584→		if l == 1 && len(samples.Histograms) > 0 {
585→			return enh.Out, annotations.New().Add(annotations.NewHistogramIgnoredInMixedRangeInfo(getMetricName(samples.Metric), args[0].PositionRange()))
586→		}
587→		return enh.Out, nil
588→	}
589→
590→	var s0, s1, b float64
591→	// Set initial values.
592→	s1 = samples.Floats[0].F
593→	b = samples.Floats[1].F - samples.Floats[0].F
594→
595→	// Run the smoothing operation.
596→	var x, y float64
597→	for i := 1; i < l; i++ {
598→		// Scale the raw value against the smoothing factor.
599→		x = sf * samples.Floats[i].F

