1290→// resetHistograms prepares the histogram caches by splitting the given vector into native and classic histograms.
1291→func (enh *EvalNodeHelper) resetHistograms(inVec Vector, arg parser.Expr) annotations.Annotations {
1292→	var annos annotations.Annotations
1293→
1294→	if enh.signatureToMetricWithBuckets == nil {
1295→		enh.signatureToMetricWithBuckets = map[string]*metricWithBuckets{}
1296→	} else {
1297→		for _, v := range enh.signatureToMetricWithBuckets {
1298→			v.buckets = v.buckets[:0]
1299→		}
1300→	}
1301→	enh.nativeHistogramSamples = enh.nativeHistogramSamples[:0]
1302→
1303→	for _, sample := range inVec {
1304→		// We are only looking for classic buckets here. Remember
1305→		// the histograms for later treatment.
1306→		if sample.H != nil {
1307→			enh.nativeHistogramSamples = append(enh.nativeHistogramSamples, sample)
1308→			continue
1309→		}
1310→
1311→		upperBound, err := strconv.ParseFloat(
1312→			sample.Metric.Get(model.BucketLabel), 64,
1313→		)
1314→		if err != nil {
1315→			if enh.enableDelayedNameRemoval {
1316→				annos.Add(annotations.NewBadBucketLabelWarning(sample.Metric.Get(labels.MetricName), sample.Metric.Get(model.BucketLabel), arg.PositionRange()))
1317→			} else {
1318→				annos.Add(annotations.NewBadBucketLabelWarning("", sample.Metric.Get(model.BucketLabel), arg.PositionRange()))
1319→			}
1320→			continue
1321→		}
1322→		enh.lblBuf = sample.Metric.BytesWithoutLabels(enh.lblBuf, labels.BucketLabel)
1323→		mb, ok := enh.signatureToMetricWithBuckets[string(enh.lblBuf)]
1324→		if !ok {
1325→			sample.Metric = labels.NewBuilder(sample.Metric).
1326→				Del(excludedLabels...).
1327→				Labels()
1328→			mb = &metricWithBuckets{sample.Metric, nil}
1329→			enh.signatureToMetricWithBuckets[string(enh.lblBuf)] = mb
1330→		}
1331→		mb.buckets = append(mb.buckets, Bucket{upperBound, sample.F})
1332→	}
1333→
1334→	for idx, sample := range enh.nativeHistogramSamples {
1335→		// We have to reconstruct the exact same signature as above for
1336→		// a classic histogram, just ignoring any le label.
1337→		enh.lblBuf = sample.Metric.Bytes(enh.lblBuf)
1338→		if mb, ok := enh.signatureToMetricWithBuckets[string(enh.lblBuf)]; ok && len(mb.buckets) > 0 {
1339→			// At this data point, we have classic histogram
1340→			// buckets and a native histogram with the same name and
1341→			// labels. Do not evaluate anything.
1342→			if enh.enableDelayedNameRemoval {
1343→				annos.Add(annotations.NewMixedClassicNativeHistogramsWarning(sample.Metric.Get(labels.MetricName), arg.PositionRange()))
1344→			} else {
1345→				annos.Add(annotations.NewMixedClassicNativeHistogramsWarning("", arg.PositionRange()))
1346→			}
1347→			delete(enh.signatureToMetricWithBuckets, string(enh.lblBuf))
1348→			enh.nativeHistogramSamples[idx].H = nil
1349→			continue
1350→		}
1351→	}
1352→	return annos
1353→}
