1597→			if aggExpr.Op != parser.TOPK && aggExpr.Op != parser.BOTTOMK && aggExpr.Op != parser.LIMITK && aggExpr.Op != parser.LIMIT_RATIO {
1598→				m := generateGroupingLabels(enh, series.Metric, aggExpr.Without, sortedGrouping)
