1600→			}
1601→			index = groupCount
1602→			groupToResultIndex[groupingKey] = index
1603→			groupCount++
1604→		}
1605→		seriesToResult[si] = index
1606→	}
1607→	groups := make([]groupedAggregation, groupCount)
1608→
1609→	var seriess map[uint64]Series
1610→
1611→	switch aggExpr.Op {
1612→	case parser.TOPK, parser.BOTTOMK, parser.LIMITK:
1613→		// Return early if all k values are less than one.
1614→		if params.Max() < 1 {
1615→			return nil, annos
1616→		}
1617→		if params.HasAnyNaN() {
1618→			ev.errorf("Parameter value is NaN")
1619→		}
1620→		if fParam := params.Min(); fParam <= minInt64 {
1621→			ev.errorf("Scalar value %v underflows int64", fParam)
1622→		}
1623→		if fParam := params.Max(); fParam >= maxInt64 {
1624→			ev.errorf("Scalar value %v overflows int64", fParam)
1625→		}
1626→		seriess = make(map[uint64]Series, len(inputMatrix))
1627→
1628→	case parser.LIMIT_RATIO:
1629→		// Return early if all r values are zero.
1630→		if params.Max() == 0 && params.Min() == 0 {
1631→			return nil, annos
1632→		}
1633→		if params.HasAnyNaN() {
1634→			ev.errorf("Ratio value is NaN")
1635→		}
1636→		if params.Max() > 1.0 {
1637→			annos.Add(annotations.NewInvalidRatioWarning(params.Max(), 1.0, aggExpr.Param.PositionRange()))
1638→		}
1639→		if params.Min() < -1.0 {
1640→			annos.Add(annotations.NewInvalidRatioWarning(params.Min(), -1.0, aggExpr.Param.PositionRange()))
1641→		}
1642→		seriess = make(map[uint64]Series, len(inputMatrix))
1643→
1644→	case parser.QUANTILE:
1645→		if params.HasAnyNaN() {
1646→			annos.Add(annotations.NewInvalidQuantileWarning(math.NaN(), aggExpr.Param.PositionRange()))
1647→		}
1648→		if params.Max() > 1 {
1649→			annos.Add(annotations.NewInvalidQuantileWarning(params.Max(), aggExpr.Param.PositionRange()))
1650→		}
1651→		if params.Min() < 0 {
1652→			annos.Add(annotations.NewInvalidQuantileWarning(params.Min(), aggExpr.Param.PositionRange()))
1653→		}
1654→	}
1655→
1656→	for ts := ev.startTimestamp; ts <= ev.endTimestamp; ts += ev.interval {
1657→		fParam := params.Next()
1658→		if err := contextDone(ctx, "expression evaluation"); err != nil {
1659→			ev.error(err)
1660→		}
1661→		// Reset number of samples in memory after each timestamp.
1662→		ev.currentSamples = tempNumSamples
1663→
1664→		// Make the function call.
1665→		enh.Ts = ts
1666→		var ws annotations.Annotations
1667→		switch aggExpr.Op {
1668→		case parser.TOPK, parser.BOTTOMK, parser.LIMITK, parser.LIMIT_RATIO:
1669→			result, ws = ev.aggregationK(aggExpr, fParam, inputMatrix, seriesToResult, groups, enh, seriess)
