1675→		default:
1676→			ws = ev.aggregation(aggExpr, fParam, inputMatrix, result, seriesToResult, groups, enh)
1677→		}
1678→
1679→		annos.Merge(ws)
1680→
1681→		if ev.currentSamples > ev.maxSamples {
1682→			ev.error(ErrTooManySamples(env))
1683→		}
1684→	}
1685→
1686→	// Assemble the output matrix. By the time we get here we know we don't have too many samples.
1687→	switch aggExpr.Op {
1688→	case parser.TOPK, parser.BOTTOMK, parser.LIMITK, parser.LIMIT_RATIO:
1689→		result = make(Matrix, 0, len(seriess))
1690→		for _, ss := range seriess {
1691→			result = append(result, ss)
1692→		}
1693→	default:
