1707→// smoothSeries is a helper function that smooths the series by interpolating the values
1708→// based on values before and after the timestamp.
1709→func (ev *evaluator) smoothSeries(series []storage.Series, offset time.Duration) Matrix {
1710→	dur := ev.endTimestamp - ev.startTimestamp
1711→
1712→	it := storage.NewBuffer(dur + 2*durationMilliseconds(ev.lookbackDelta))
1713→
1714→	offMS := offset.Milliseconds()
1715→	start := ev.startTimestamp - offMS
1716→	end := ev.endTimestamp - offMS
1717→	step := ev.interval
1718→	lb := durationMilliseconds(ev.lookbackDelta)
1719→
1720→	var chkIter chunkenc.Iterator
1721→	mat := make(Matrix, 0, len(series))
1722→
1723→	for _, s := range series {
1724→		ss := Series{Metric: s.Labels()}
1725→
1726→		chkIter = s.Iterator(chkIter)
1727→		it.Reset(chkIter)
1728→
1729→		var floats []FPoint
1730→		var hists []HPoint
1731→
1732→		for ts := start; ts <= end; ts += step {
1733→			matrixStart := ts - lb
1734→			matrixEnd := ts + lb
1735→
1736→			floats, hists = ev.matrixIterSlice(it, matrixStart, matrixEnd, floats, hists)
1737→			if len(floats) == 0 && len(hists) == 0 {
1738→				continue
1739→			}
1740→
1741→			if len(hists) > 0 {
1742→				// TODO: support native histograms.
1743→				ev.errorf("smoothed and anchored modifiers do not work with native histograms")
1744→			}
1745→
1746→			// Binary search for the first index with T >= ts.
1747→			i := sort.Search(len(floats), func(i int) bool { return floats[i].T >= ts })
1748→
1749→			switch {
1750→			case i < len(floats) && floats[i].T == ts:
1751→				// Exact match.
1752→				ss.Floats = append(ss.Floats, floats[i])
1753→
1754→			case i > 0 && i < len(floats):
1755→				// Interpolate between prev and next.
1756→				// TODO: detect if the sample is a counter, based on __type__ or metadata.
1757→				prev, next := floats[i-1], floats[i]
1758→				val := interpolate(prev, next, ts, false)
1759→				ss.Floats = append(ss.Floats, FPoint{F: val, T: ts})
1760→
1761→			case i > 0:
1762→				// No next point yet; carry forward previous value.
1763→				prev := floats[i-1]
1764→				ss.Floats = append(ss.Floats, FPoint{F: prev.F, T: ts})
1765→
1766→			default:
1767→				// i == 0 and floats[0].T > ts: there is no previous data yet; skip.
1768→			}
1769→		}
1770→
1771→		mat = append(mat, ss)
1772→	}
1773→
1774→	return mat
1775→}
