642→// === sort_by_label(vector parser.ValueTypeVector, label parser.ValueTypeString...) (Vector, Annotations) ===
643→func funcSortByLabel(vectorVals []Vector, _ Matrix, args parser.Expressions, _ *EvalNodeHelper) (Vector, annotations.Annotations) {
644→	lbls := stringSliceFromArgs(args[1:])
645→	slices.SortFunc(vectorVals[0], func(a, b Sample) int {
646→		for _, label := range lbls {
647→			lv1 := a.Metric.Get(label)
648→			lv2 := b.Metric.Get(label)
649→
650→			if lv1 == lv2 {
651→				continue
652→			}
653→
654→			if natsort.Compare(lv1, lv2) {
655→				return -1
656→			}
657→
658→			return +1
659→		}
660→
661→		// If all labels provided as arguments were equal, sort by the full label set. This ensures a consistent ordering.
662→		return labels.Compare(a.Metric, b.Metric)
663→	})
664→
665→	return vectorVals[0], nil
666→}
