671→	slices.SortFunc(vectorVals[0], func(a, b Sample) int {
672→		for _, label := range lbls {
673→			lv1 := a.Metric.Get(label)
674→			lv2 := b.Metric.Get(label)
675→
676→			if lv1 == lv2 {
677→				continue
678→			}
