694→func clamp(vec Vector, minVal, maxVal float64, enh *EvalNodeHelper) (Vector, annotations.Annotations) {
695→	if maxVal < minVal {
696→		return enh.Out, nil
697→	}
698→	for _, el := range vec {
699→		if el.H != nil {
700→			// Process only float samples.
701→			continue
702→		}
703→		if !enh.enableDelayedNameRemoval {
704→			el.Metric = el.Metric.DropReserved(schema.IsMetadataLabel)
705→		}
706→		enh.Out = append(enh.Out, Sample{
707→			Metric:   el.Metric,
708→			F:        math.Max(minVal, math.Min(maxVal, el.F)),
709→			DropName: true,
710→		})
711→	}
712→	return enh.Out, nil
713→}
