737→// === round(Vector parser.ValueTypeVector, toNearest=1 Scalar) (Vector, Annotations) ===
738→func funcRound(vectorVals []Vector, _ Matrix, args parser.Expressions, enh *EvalNodeHelper) (Vector, annotations.Annotations) {
739→	// round returns a number rounded to toNearest.
740→	// Ties are solved by rounding up.
741→	toNearest := float64(1)
742→	if len(args) >= 2 {
743→		toNearest = vectorVals[1][0].F
744→	}
745→	// Invert as it seems to cause fewer floating point accuracy issues.
746→	toNearestInverse := 1.0 / toNearest
747→	return simpleFloatFunc(vectorVals, enh, func(f float64) float64 {
748→		return math.Floor(f*toNearestInverse+0.5) / toNearestInverse
749→	}), nil
750→}
