752→// === Scalar(node parser.ValueTypeVector) Scalar ===
753→func funcScalar(vectorVals []Vector, _ Matrix, _ parser.Expressions, enh *EvalNodeHelper) (Vector, annotations.Annotations) {
754→	var (
755→		v     = vectorVals[0]
756→		value float64
757→		found bool
758→	)
759→
760→	for _, s := range v {
761→		if s.H == nil {
762→			if found {
763→				// More than one float found, return NaN.
764→				return append(enh.Out, Sample{F: math.NaN()}), nil
765→			}
766→			found = true
767→			value = s.F
768→		}
769→	}
770→	// Return the single float if found, otherwise return NaN.
771→	if !found {
772→		return append(enh.Out, Sample{F: math.NaN()}), nil
773→	}
774→	return append(enh.Out, Sample{F: value}), nil
775→}
