796→// === avg_over_time(Matrix parser.ValueTypeMatrix) (Vector, Annotations)  ===
797→func funcAvgOverTime(_ []Vector, matrixVal Matrix, args parser.Expressions, enh *EvalNodeHelper) (Vector, annotations.Annotations) {
798→	if len(matrixVal) == 0 {
799→		return enh.Out, nil
800→	}
801→	firstSeries := matrixVal[0]
802→	if len(firstSeries.Floats) > 0 && len(firstSeries.Histograms) > 0 {
803→		return enh.Out, annotations.New().Add(annotations.NewMixedFloatsHistogramsWarning(getMetricName(firstSeries.Metric), args[0].PositionRange()))
804→	}
805→	// We improve the accuracy with the help of Kahan summation.
806→	// For a while, we assumed that incremental mean calculation combined
807→	// with Kahan summation (see
808→	// https://stackoverflow.com/questions/61665473/is-it-beneficial-for-precision-to-calculate-the-incremental-mean-average
809→	// for inspiration) is generally the preferred solution. However, it
810→	// then turned out that direct mean calculation (still in combination
811→	// with Kahan summation) is often more accurate. See discussion in
812→	// https://github.com/prometheus/prometheus/issues/16714 . The problem
813→	// with the direct mean calculation is that it can overflow float64 for
814→	// inputs on which the incremental mean calculation works just fine. Our
815→	// current approach is therefore to use direct mean calculation as long
816→	// as we do not overflow (or underflow) the running sum. Once the latter
817→	// would happen, we switch to incremental mean calculation. This seems
818→	// to work reasonably well, but note that a deeper understanding would
819→	// be needed to find out if maybe an earlier switch to incremental mean
820→	// calculation would be better in terms of accuracy. Also, we could
821→	// apply a number of additional means to improve the accuracy, like
822→	// processing the values in a particular order. For now, we decided that
823→	// the current implementation is accurate enough for practical purposes.
824→	if len(firstSeries.Floats) == 0 {
825→		// The passed values only contain histograms.
826→		var annos annotations.Annotations
827→		vec, err := aggrHistOverTime(matrixVal, enh, func(s Series) (*histogram.FloatHistogram, error) {
828→			var counterResetSeen, notCounterResetSeen, nhcbBoundsReconciledSeen bool
829→
830→			trackCounterReset := func(h *histogram.FloatHistogram) {
831→				switch h.CounterResetHint {
832→				case histogram.CounterReset:
833→					counterResetSeen = true
834→				case histogram.NotCounterReset:
835→					notCounterResetSeen = true
836→				}
837→			}
838→
839→			defer func() {
840→				if counterResetSeen && notCounterResetSeen {
841→					annos.Add(annotations.NewHistogramCounterResetCollisionWarning(args[0].PositionRange(), annotations.HistogramAgg))
842→				}
843→				if nhcbBoundsReconciledSeen {
