861→					sumCopy := sum.Copy()
862→					var cCopy *histogram.FloatHistogram
863→					if kahanC != nil {
864→						cCopy = kahanC.Copy()
865→					}
866→					cCopy, _, nhcbBoundsReconciled, err = sumCopy.KahanAdd(h.H, cCopy)
