1530→// === deriv(node parser.ValueTypeMatrix) (Vector, Annotations) ===
1531→func funcDeriv(_ []Vector, matrixVal Matrix, args parser.Expressions, enh *EvalNodeHelper) (Vector, annotations.Annotations) {
1532→	if len(matrixVal) == 0 {
1533→		return enh.Out, nil
1534→	}
1535→	samples := matrixVal[0]
1536→
1537→	// No sense in trying to compute a derivative without at least two float points.
1538→	// Drop this Vector element.
1539→	if len(samples.Floats) < 2 {
1540→		// Annotate mix of float and histogram.
1541→		if len(samples.Floats) == 1 && len(samples.Histograms) > 0 {
1542→			return enh.Out, annotations.New().Add(annotations.NewHistogramIgnoredInMixedRangeInfo(getMetricName(samples.Metric), args[0].PositionRange()))
1543→		}
1544→		return enh.Out, nil
1545→	}
1546→
1547→	// We pass in an arbitrary timestamp that is near the values in use
1548→	// to avoid floating point accuracy issues, see
1549→	// https://github.com/prometheus/prometheus/issues/2674
1550→	slope, _ := linearRegression(samples.Floats, samples.Floats[0].T)
1551→	if len(samples.Histograms) > 0 {
1552→		return append(enh.Out, Sample{F: slope}), annotations.New().Add(annotations.NewHistogramIgnoredInMixedRangeInfo(getMetricName(samples.Metric), args[0].PositionRange()))
1553→	}
1554→	return append(enh.Out, Sample{F: slope}), nil
1555→}
