1557→// === predict_linear(node parser.ValueTypeMatrix, k parser.ValueTypeScalar) (Vector, Annotations) ===
1558→func funcPredictLinear(vectorVals []Vector, matrixVal Matrix, args parser.Expressions, enh *EvalNodeHelper) (Vector, annotations.Annotations) {
1559→	if len(vectorVals) == 0 || len(vectorVals[0]) == 0 || len(matrixVal) == 0 {
1560→		return enh.Out, nil
1561→	}
1562→	samples := matrixVal[0]
1563→	duration := vectorVals[0][0].F
1564→
1565→	// No sense in trying to predict anything without at least two float points.
1566→	// Drop this Vector element.
1567→	if len(samples.Floats) < 2 {
1568→		// Annotate mix of float and histogram.
1569→		if len(samples.Floats) == 1 && len(samples.Histograms) > 0 {
1570→			return enh.Out, annotations.New().Add(annotations.NewHistogramIgnoredInMixedRangeInfo(getMetricName(samples.Metric), args[0].PositionRange()))
1571→		}
1572→		return enh.Out, nil
1573→	}
1574→
1575→	slope, intercept := linearRegression(samples.Floats, enh.Ts)
1576→	if len(samples.Histograms) > 0 {
1577→		return append(enh.Out, Sample{F: slope*duration + intercept}), annotations.New().Add(annotations.NewHistogramIgnoredInMixedRangeInfo(getMetricName(samples.Metric), args[0].PositionRange()))
1578→	}
1579→	return append(enh.Out, Sample{F: slope*duration + intercept}), nil
1580→}
