1619→func histogramVariance(vectorVals []Vector, enh *EvalNodeHelper, varianceToResult func(float64) float64) (Vector, annotations.Annotations) {
1620→	return simpleHistogramFunc(vectorVals, enh, func(h *histogram.FloatHistogram) float64 {
1621→		mean := h.Sum / h.Count
1622→		var variance, cVariance float64
1623→		it := h.AllBucketIterator()
1624→		for it.Next() {
1625→			bucket := it.At()
1626→			if bucket.Count == 0 {
1627→				continue
1628→			}
1629→			var val float64
1630→			switch {
1631→			case h.UsesCustomBuckets():
1632→				// Use arithmetic mean in case of custom buckets.
1633→				val = (bucket.Upper + bucket.Lower) / 2.0
1634→			case bucket.Lower <= 0 && bucket.Upper >= 0:
1635→				// Use zero (effectively the arithmetic mean) in the zero bucket of a standard exponential histogram.
1636→				val = 0
1637→			default:
1638→				// Use geometric mean in case of standard exponential buckets.
1639→				val = math.Sqrt(bucket.Upper * bucket.Lower)
1640→				if bucket.Upper < 0 {
1641→					val = -val
1642→				}
1643→			}
1644→			delta := val - mean
1645→			variance, cVariance = kahansum.Inc(bucket.Count*delta*delta, variance, cVariance)
1646→		}
1647→		variance += cVariance
1648→		variance /= h.Count
1649→		if varianceToResult != nil {
1650→			variance = varianceToResult(variance)
1651→		}
1652→		return variance
1653→	}), nil
1654→}
