1931→	histograms := matrixVal[0].Histograms
1932→	changes := 0
1933→	if len(floats) == 0 && len(histograms) == 0 {
1934→		return enh.Out, nil
1935→	}
1936→
1937→	var prevSample, curSample Sample
1938→	firstSampleIndex, found := pickFirstSampleIndex(floats, args, enh)
1939→	if !found {
1940→		return enh.Out, nil
1941→	}
1942→	for iFloat, iHistogram := firstSampleIndex, 0; iFloat < len(floats) || iHistogram < len(histograms); {
1943→		switch {
1944→		// Process a float sample if no histogram sample remains or its timestamp is earlier.
1945→		// Process a histogram sample if no float sample remains or its timestamp is earlier.
1946→		case iHistogram >= len(histograms) || iFloat < len(floats) && floats[iFloat].T < histograms[iHistogram].T:
1947→			curSample.F = floats[iFloat].F
1948→			curSample.H = nil
1949→			iFloat++
1950→		case iFloat >= len(floats) || iHistogram < len(histograms) && floats[iFloat].T > histograms[iHistogram].T:
1951→			curSample.H = histograms[iHistogram].H
1952→			iHistogram++
1953→		}
1954→		// Skip the comparison for the first sample, just initialize prevSample.
1955→		if iFloat+iHistogram == 1+firstSampleIndex {
1956→			prevSample = curSample
1957→			continue
1958→		}
1959→		switch {
1960→		case prevSample.H == nil && curSample.H == nil:
1961→			if curSample.F != prevSample.F && !(math.IsNaN(curSample.F) && math.IsNaN(prevSample.F)) {
1962→				changes++
1963→			}
1964→		case prevSample.H != nil && curSample.H == nil, prevSample.H == nil && curSample.H != nil:
1965→			changes++
1966→		case prevSample.H != nil && curSample.H != nil:
1967→			if !curSample.H.Equals(prevSample.H) {
