1977→// label_replace function operates only on series; does not look at timestamps or values.
1978→func (ev *evaluator) evalLabelReplace(ctx context.Context, args parser.Expressions) (parser.Value, annotations.Annotations) {
1979→	var (
1980→		dst      = stringFromArg(args[1])
1981→		repl     = stringFromArg(args[2])
1982→		src      = stringFromArg(args[3])
1983→		regexStr = stringFromArg(args[4])
1984→	)
1985→
1986→	regex, err := regexp.Compile("^(?s:" + regexStr + ")$")
1987→	if err != nil {
1988→		panic(fmt.Errorf("invalid regular expression in label_replace(): %s", regexStr))
1989→	}
1990→	if !model.UTF8Validation.IsValidLabelName(dst) {
1991→		panic(fmt.Errorf("invalid destination label name in label_replace(): %s", dst))
1992→	}
1993→
1994→	val, ws := ev.eval(ctx, args[0])
1995→	matrix := val.(Matrix)
1996→	lb := labels.NewBuilder(labels.EmptyLabels())
1997→
1998→	for i, el := range matrix {
1999→		srcVal := el.Metric.Get(src)
2000→		indexes := regex.FindStringSubmatchIndex(srcVal)
2001→		if indexes != nil { // Only replace when regexp matches.
2002→			res := regex.ExpandString([]byte{}, repl, srcVal, indexes)
2003→			lb.Reset(el.Metric)
2004→			lb.Set(dst, string(res))
2005→			matrix[i].Metric = lb.Labels()
2006→			if dst == model.MetricNameLabel {
2007→				matrix[i].DropName = false
2008→			} else {
2009→				matrix[i].DropName = el.DropName
2010→			}
2011→		}
2012→	}
2013→
2014→	return ev.mergeSeriesWithSameLabelset(matrix), ws
2015→}
