2026→// label_join function operates only on series; does not look at timestamps or values.
2027→func (ev *evaluator) evalLabelJoin(ctx context.Context, args parser.Expressions) (parser.Value, annotations.Annotations) {
2028→	var (
2029→		dst       = stringFromArg(args[1])
2030→		sep       = stringFromArg(args[2])
2031→		srcLabels = make([]string, len(args)-3)
2032→	)
2033→	for i := 3; i < len(args); i++ {
2034→		src := stringFromArg(args[i])
2035→		if !model.UTF8Validation.IsValidLabelName(src) {
2036→			panic(fmt.Errorf("invalid source label name in label_join(): %s", src))
2037→		}
2038→		srcLabels[i-3] = src
2039→	}
2040→	if !model.UTF8Validation.IsValidLabelName(dst) {
2041→		panic(fmt.Errorf("invalid destination label name in label_join(): %s", dst))
2042→	}
2043→
2044→	val, ws := ev.eval(ctx, args[0])
2045→	matrix := val.(Matrix)
2046→	srcVals := make([]string, len(srcLabels))
2047→	lb := labels.NewBuilder(labels.EmptyLabels())
2048→
2049→	for i, el := range matrix {
2050→		for i, src := range srcLabels {
2051→			srcVals[i] = el.Metric.Get(src)
2052→		}
2053→		strval := strings.Join(srcVals, sep)
2054→		lb.Reset(el.Metric)
2055→		lb.Set(dst, strval)
2056→		matrix[i].Metric = lb.Labels()
2057→
2058→		if dst == model.MetricNameLabel {
2059→			matrix[i].DropName = false
2060→		} else {
2061→			matrix[i].DropName = el.DropName
2062→		}
2063→	}
2064→
2065→	return ev.mergeSeriesWithSameLabelset(matrix), ws
2066→}
