2362→			currentSamples:           ev.currentSamples,
2363→			maxSamples:               ev.maxSamples,
2364→			logger:                   ev.logger,
2365→			lookbackDelta:            ev.lookbackDelta,
2366→			samplesStats:             ev.samplesStats.NewChild(),
2367→			noStepSubqueryIntervalFn: ev.noStepSubqueryIntervalFn,
2368→			enableDelayedNameRemoval: ev.enableDelayedNameRemoval,
2369→			enableTypeAndUnitLabels:  ev.enableTypeAndUnitLabels,
2370→			querier:                  ev.querier,
2371→		}
2372→
2373→		if e.Step != 0 {
2374→			newEv.interval = durationMilliseconds(e.Step)
2375→		} else {
2376→			newEv.interval = ev.noStepSubqueryIntervalFn(rangeMillis)
2377→		}
2378→
2379→		// Start with the first timestamp after (ev.startTimestamp - offset - range)
2380→		// that is aligned with the step (multiple of 'newEv.interval').
2381→		newEv.startTimestamp = newEv.interval * ((ev.startTimestamp - offsetMillis - rangeMillis) / newEv.interval)
2382→		if newEv.startTimestamp <= (ev.startTimestamp - offsetMillis - rangeMillis) {
2383→			newEv.startTimestamp += newEv.interval
2384→		}
2385→
2386→		if newEv.startTimestamp != ev.startTimestamp {
2387→			// Adjust the offset of selectors based on the new
2388→			// start time of the evaluator since the calculation
2389→			// of the offset with @ happens w.r.t. the start time.
2390→			setOffsetForAtModifier(newEv.startTimestamp, e.Expr)
2391→		}
2392→
2393→		res, ws := newEv.eval(ctx, e.Expr)
2394→		ev.currentSamples = newEv.currentSamples
2395→		ev.samplesStats.UpdatePeakFromSubquery(newEv.samplesStats)
2396→		ev.samplesStats.IncrementSamplesAtTimestamp(ev.endTimestamp, newEv.samplesStats.TotalSamples)
2397→		return res, ws
2398→	case *parser.StepInvariantExpr:
2399→		newEv := &evaluator{
2400→			startTimestamp:           ev.startTimestamp,
2401→			endTimestamp:             ev.startTimestamp, // Always a single evaluation.
2402→			interval:                 ev.interval,
2403→			currentSamples:           ev.currentSamples,
2404→			maxSamples:               ev.maxSamples,
2405→			logger:                   ev.logger,
2406→			lookbackDelta:            ev.lookbackDelta,
2407→			samplesStats:             ev.samplesStats.NewChild(),
2408→			noStepSubqueryIntervalFn: ev.noStepSubqueryIntervalFn,
2409→			enableDelayedNameRemoval: ev.enableDelayedNameRemoval,
2410→			enableTypeAndUnitLabels:  ev.enableTypeAndUnitLabels,
2411→			querier:                  ev.querier,
2412→		}
2413→		res, ws := newEv.eval(ctx, e.Expr)
2414→		ev.currentSamples = newEv.currentSamples
2415→		ev.samplesStats.UpdatePeakFromSubquery(newEv.samplesStats)
2416→		for ts, step := ev.startTimestamp, -1; ts <= ev.endTimestamp; ts += ev.interval {
2417→			step++
2418→			ev.samplesStats.IncrementSamplesAtStep(step, newEv.samplesStats.TotalSamples)
2419→		}
2420→		switch e.Expr.(type) {
2421→		case *parser.MatrixSelector, *parser.SubqueryExpr:
2422→			// We do not duplicate results for range selectors since result is a matrix
2423→			// with their unique timestamps which does not depend on the step.
2424→			return res, ws
2425→		}
2426→
2427→		// For every evaluation while the value remains same, the timestamp for that
2428→		// value would change for different eval times. Hence we duplicate the result
2429→		// with changed timestamps.
2430→		mat, ok := res.(Matrix)
2431→		if !ok {
2432→			panic(fmt.Errorf("unexpected result in StepInvariantExpr evaluation: %T", expr))
2433→		}
2434→		for i := range mat {
2435→			if len(mat[i].Floats)+len(mat[i].Histograms) != 1 {
2436→				panic(errors.New("unexpected number of samples"))
2437→			}
2438→			for ts := ev.startTimestamp + ev.interval; ts <= ev.endTimestamp; ts += ev.interval {
2439→				if len(mat[i].Floats) > 0 {
2440→					mat[i].Floats = append(mat[i].Floats, FPoint{
2441→						T: ts,
2442→						F: mat[i].Floats[0].F,
2443→					})
2444→					ev.currentSamples++
2445→				} else {
2446→					point := HPoint{
2447→						T: ts,
2448→						H: mat[i].Histograms[0].H,
2449→					}
2450→					mat[i].Histograms = append(mat[i].Histograms, point)
2451→					ev.currentSamples += point.size()
2452→				}
2453→				if ev.currentSamples > ev.maxSamples {
2454→					ev.error(ErrTooManySamples(env))
2455→				}
2456→			}
2457→		}
2458→		ev.samplesStats.UpdatePeak(ev.currentSamples)
2459→		return res, ws
2460→	}
2461→
2462→	panic(fmt.Errorf("unhandled expression of type: %T", expr))
2463→}
