2489→func (ev *evaluator) rangeEvalTimestampFunctionOverVectorSelector(ctx context.Context, vs *parser.VectorSelector, call FunctionCall, e *parser.Call) (parser.Value, annotations.Annotations) {
2490→	ws, err := checkAndExpandSeriesSet(ctx, vs)
2491→	if err != nil {
2492→		ev.error(errWithWarnings{fmt.Errorf("expanding series: %w", err), ws})
2493→	}
2494→
2495→	seriesIterators := make([]*storage.MemoizedSeriesIterator, len(vs.Series))
2496→	for i, s := range vs.Series {
2497→		it := s.Iterator(nil)
2498→		seriesIterators[i] = storage.NewMemoizedIterator(it, durationMilliseconds(ev.lookbackDelta)-1)
2499→	}
